import { ImageResponse } from '@vercel/og';

export const config = { runtime: 'edge' };

export default function handler(req) {
  const url = new URL(req.url);
  const host = url.host;
  const d = url.searchParams.get('d');
  if (!d || !M[d]) return new Response(null, { status: 302, headers: { Location: '/og-image.png' } });
  const p = P[M[d]];
  if (!p) return new Response(null, { status: 302, headers: { Location: '/og-image.png' } });

  const accent = p.cat === 'meme' ? '#ff6b35' : p.cat === 'stable' ? '#4a9eff' : '#00d4aa';
  const bg1 = p.cat === 'meme' ? '#1a0800' : p.cat === 'stable' ? '#000a1a' : '#001a10';
  const title = p.pt;
  const trans = p.tr.length > 80 ? p.tr.substring(0, p.tr.lastIndexOf(' ', 80)) + '...' : p.tr;
  const cat = p.cat.toUpperCase();
  const coin = p.cn + ' (' + p.t + ')';

  return new ImageResponse(
    {
      type: 'div',
      props: {
        style: {
          width: '100%', height: '100%', display: 'flex', flexDirection: 'column',
          background: 'linear-gradient(135deg, ' + bg1 + ', #0a0a0f)',
          padding: '48px', fontFamily: 'sans-serif', position: 'relative',
        },
        children: [
          { type: 'div', props: { style: { position: 'absolute', top: 0, left: 0, right: 0, height: '3px', background: accent } } },
          { type: 'div', props: { style: { display: 'flex', padding: '4px 12px', borderRadius: '6px', background: accent + '26', color: accent, fontSize: '13px', fontWeight: 700, letterSpacing: '2px', alignSelf: 'flex-start' }, children: cat } },
          { type: 'div', props: { style: { color: accent, fontSize: '22px', fontWeight: 700, marginTop: '20px' }, children: coin } },
          { type: 'div', props: { style: { color: '#ffffff', fontSize: '52px', fontWeight: 800, marginTop: '16px', lineHeight: 1.1 }, children: title } },
          { type: 'div', props: { style: { color: 'rgba(255,255,255,0.5)', fontSize: '20px', fontStyle: 'italic', marginTop: '16px', lineHeight: 1.4 }, children: trans } },
          { type: 'div', props: { style: { flex: 1 } } },
          { type: 'div', props: {
            style: { display: 'flex', justifyContent: 'space-between', alignItems: 'center', background: 'rgba(0,0,0,0.4)', margin: '0 -48px -48px -48px', padding: '20px 48px' },
            children: [
              { type: 'div', props: { style: { color: 'rgba(255,255,255,0.35)', fontSize: '15px', fontWeight: 700 }, children: 'WHAT CRYPTO ARE YOU?' } },
              { type: 'div', props: { style: { color: accent, fontSize: '15px', fontWeight: 700 }, children: host } },
            ],
          }},
        ],
      },
    },
    { width: 1200, height: 630, headers: { 'Cache-Control': 'public, max-age=86400, s-maxage=86400' } },
  );
}
